import{_ as r,o as a,c as s,ag as n,ah as o}from"./chunks/framework.D9bIGSBm.js";const b=JSON.parse('{"title":"机器人渠道","description":"","frontmatter":{},"headers":[],"relativePath":"settings/bots.md","filePath":"settings/bots.md"}'),e={name:"settings/bots.md"};function l(i,t,d,g,h,p){return a(),s("div",null,[...t[0]||(t[0]=[n('<h1 id="机器人渠道" tabindex="-1">机器人渠道 <a class="header-anchor" href="#机器人渠道" aria-label="Permalink to &quot;机器人渠道&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏底部 → 手机图标（<strong>移动端支持</strong>）</p><blockquote><p>机器人渠道的配置入口<strong>不在设置面板内</strong>，而是侧边栏底部工具栏上的手机图标按钮（悬停显示&quot;移动端支持&quot;），点击后弹出独立的机器人管理对话框。</p></blockquote><div class="warning custom-block"><p class="custom-block-title">安全提醒：消息即操作权限</p><p>机器人渠道会把即时通讯消息直接转发给 AI 执行。<strong>任何能向绑定账号发送消息的人，都可能触发 AI 在你的电脑上执行操作——包括修改、删除文件和运行命令。</strong> 请仅在完全私密的私聊中使用，不要把绑定账号加入群组；如确需使用飞书的群聊 @ 功能，请确保群内所有成员都完全可信。</p></div><p>机器人渠道让你把即时通讯工具接入 LoongCode，在离开电脑时也可以通过手机发送消息来新建任务、驱动 AI 执行代码操作、并接收回复。目前支持 <strong>微信 ClawBot</strong>（通过微信账号扫码绑定）和 <strong>飞书</strong>（通过飞书应用扫码绑定）两种渠道。</p><p><img src="'+o+'" alt="机器人渠道管理对话框，左侧为机器人列表，右侧为选中机器人的详情面板"></p><hr><h2 id="机器人列表" tabindex="-1">机器人列表 <a class="header-anchor" href="#机器人列表" aria-label="Permalink to &quot;机器人列表&quot;">​</a></h2><p>对话框左侧显示已配置的机器人列表。每条记录显示：</p><ul><li>渠道图标（微信或飞书）</li><li>机器人名称</li><li>渠道类型标签</li><li>连接状态灯：<strong>已连接</strong>（绿色）、<strong>重连中</strong>（黄色，仅飞书）或 <strong>未绑定</strong></li></ul><p>点击列表顶部的 <strong>+ 新建机器人</strong> 按钮进入渠道类型选择页，可选 <strong>微信 ClawBot</strong> 或 <strong>飞书</strong>。</p><hr><h2 id="详情面板" tabindex="-1">详情面板 <a class="header-anchor" href="#详情面板" aria-label="Permalink to &quot;详情面板&quot;">​</a></h2><p>点击列表中任意机器人后，右侧显示详情面板，包含以下区块：</p><h3 id="名称与状态" tabindex="-1">名称与状态 <a class="header-anchor" href="#名称与状态" aria-label="Permalink to &quot;名称与状态&quot;">​</a></h3><ul><li>显示机器人名称，点击铅笔图标可内联重命名</li><li>显示绑定状态（<strong>已连接</strong> 或 <strong>未绑定</strong>）</li><li><strong>启用该渠道</strong> 开关 — 关闭后该渠道不再接收和处理消息</li></ul><h3 id="关联机器人" tabindex="-1">关联机器人 <a class="header-anchor" href="#关联机器人" aria-label="Permalink to &quot;关联机器人&quot;">​</a></h3><p>管理与即时通讯账号的绑定关系（各渠道操作见下方章节）。</p><h3 id="机器人回复颗粒度" tabindex="-1">机器人回复颗粒度 <a class="header-anchor" href="#机器人回复颗粒度" aria-label="Permalink to &quot;机器人回复颗粒度&quot;">​</a></h3><p>控制 AI 回复的详细程度：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><strong>标准回复</strong></td><td>只回正文内容、异常信息和需要用户确认的询问</td></tr><tr><td><strong>完整回复</strong></td><td>在标准回复基础上，额外包含工具调用过程</td></tr></tbody></table><h3 id="删除机器人" tabindex="-1">删除机器人 <a class="header-anchor" href="#删除机器人" aria-label="Permalink to &quot;删除机器人&quot;">​</a></h3><p>点击 <strong>删除机器人</strong> 按钮，确认后永久移除该渠道配置，不可撤销。</p><hr><h2 id="触发任务的配置" tabindex="-1">触发任务的配置 <a class="header-anchor" href="#触发任务的配置" aria-label="Permalink to &quot;触发任务的配置&quot;">​</a></h2><p>通过机器人消息触发时，如果当前没有可续用的任务，应用会自动新建一个。这个任务<strong>沿用你的全局新建任务默认配置</strong>——CLI（Claude / Codex / OpenCode / Kimi 四家族均支持，v0.9.0 起、Kimi 自 v0.10.0 起）、模型、供应商、思考深度都与你在应用内新建任务时一致。</p><p>唯一的例外是<strong>执行授权</strong>：为保证无人值守流程不因等待审批而卡住，机器人触发的任务会把权限<strong>强制放行</strong>（Claude 使用 bypassPermissions、Codex 使用完全访问、OpenCode 使用 auto、Kimi 使用 auto），不论你的全局默认设成什么。这也正是顶部安全提醒的由来——请确保只有你自己能给绑定账号发消息。</p><hr><h2 id="接入微信-微信-clawbot" tabindex="-1">接入微信（微信 ClawBot） <a class="header-anchor" href="#接入微信-微信-clawbot" aria-label="Permalink to &quot;接入微信（微信 ClawBot）&quot;">​</a></h2><p>微信 ClawBot 通过扫码绑定你的微信账号，之后你在微信中发送的消息（或指定联系人的消息）会被转发到 LoongCode，由 AI 处理后回复。</p><p><strong>绑定步骤：</strong></p><ol><li>在机器人列表中点击目标微信 ClawBot 机器人（或新建一个）</li><li>右侧详情面板中，在 <strong>关联机器人</strong> 区块点击 <strong>重新获取二维码</strong></li><li>用 <strong>手机上的微信</strong> 扫描显示的二维码</li><li>手机弹出确认提示后点击确认，等待状态变为 <strong>已通过微信扫码绑定</strong></li></ol><p><img src="'+o+'" alt="微信 ClawBot 绑定流程，详情面板关联机器人区块显示二维码及扫码状态提示"></p><p><strong>扫码状态说明：</strong></p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>等待扫码</td><td>二维码已生成，等待手机扫描</td></tr><tr><td>已扫描，请在手机确认</td><td>已扫码，需在手机上点击确认按钮</td></tr><tr><td>已确认</td><td>绑定成功</td></tr><tr><td>二维码已过期，请重新获取</td><td>二维码超时，点击 <strong>重新获取二维码</strong> 重试</td></tr><tr><td>获取失败，请重试</td><td>服务异常，点击 <strong>重新获取二维码</strong> 重试</td></tr></tbody></table><p><strong>解除绑定：</strong> 在 <strong>关联机器人</strong> 区块点击 <strong>解绑</strong> → 确认。解绑后需重新扫码才能再次使用。</p><hr><h2 id="接入飞书" tabindex="-1">接入飞书 <a class="header-anchor" href="#接入飞书" aria-label="Permalink to &quot;接入飞书&quot;">​</a></h2><p>飞书渠道通过 LoongCode 应用内的扫码流程自动创建并绑定一个飞书自建应用，无需手动在飞书开放平台配置。绑定后支持与机器人私聊，以及在群聊中 @ 机器人触发任务。</p><p><strong>绑定步骤：</strong></p><ol><li>在机器人列表中点击目标飞书机器人（或新建一个）</li><li>右侧详情面板中，在 <strong>关联机器人</strong> 区块点击 <strong>扫码创建并绑定应用</strong></li><li>用 <strong>飞书 App</strong> 扫描显示的二维码，完成授权</li><li>状态指示灯变为绿色 <strong>已连接</strong> 表示绑定成功</li></ol><p>绑定成功后，在飞书中与机器人私聊即可直接使用；在群聊中需 <strong>@机器人</strong> 才能触发。</p><p><strong>连接状态说明：</strong></p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>已连接（绿色）</td><td>长连接正常，消息实时转发</td></tr><tr><td>重连中（黄色）</td><td>连接短暂中断，正在自动重连（指数退避）</td></tr><tr><td>未连接（灰色）</td><td>未绑定或连接断开</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>电脑从系统睡眠中唤醒后，应用会秒级检测到并自动重连飞书长连接，不必等待原有的心跳超时判定。若不想让电脑在有机器人绑定时自动进入睡眠，可在<a href="/docs/settings/mobile-pairing.html">移动端配对</a>页开启<strong>息屏保活</strong>开关（该开关同时对机器人渠道生效，不要求同时配对手机）。</p></div><p><strong>解除绑定：</strong> 在 <strong>关联机器人</strong> 区块点击 <strong>解绑</strong> → 确认。解绑后需重新扫码才能再次使用。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/mobile-pairing.html">移动端配对</a> — 通过官方 LoongCode App 远程驱动任务（支持实时事件流、历史回放与富输入）</li><li><a href="/docs/features/tasks-and-workspaces.html">任务工作区</a> — 了解通过机器人远程驱动的任务在应用内如何组织与管理</li><li><a href="/docs/reference/shortcuts.html">快捷键参考</a> — 查看应用内所有键盘快捷键</li></ul>',49)])])}const u=r(e,[["render",l]]);export{b as __pageData,u as default};
